const ctx = document.getElementById('jailbreakChart');
    new Chart(ctx, {
      type: 'bar',
      data: {
        labels: ['Gemini-2.5-Flash', 'Llama-4-Maverick', 'DeepSeek-V3.2-Speciale'],
        datasets: [
          {
            label: 'Baseline ASR',
            data: [4.33, 1.33, 11.67],
            backgroundColor: '#f6ad55',
            borderColor: '#f6ad55',
            borderWidth: 1,
            borderRadius: 6
          },
          {
            label: 'Jailbreak ASR',
            data: [33.07, 30.47, 45.33],
            backgroundColor: '#4dabf7',
            borderColor: '#4dabf7',
            borderWidth: 1,
            borderRadius: 6
          }
        ]
      },
      options: {
        animation: false,
        maintainAspectRatio: false,
        responsive: true,
        plugins: {
          legend: {
            labels: {
