            max: 50,
            grid: {
              color: '#e2e8f0'
            },
            ticks: {
              color: '#4a5568',
              callback: function(value) {
                return value + '%';
              },
              font: {
                family: 'system-ui, -apple-system, "Segoe UI", sans-serif',
                size: 11
